/* ═══════════════════════════════════════════════════════════════
 * DFT-4 K=1 — 8 add/sub, zero twiddle, zero spill
 * ═══════════════════════════════════════════════════════════════ */

static inline void dft4_k1_fwd(
    const double * __restrict__ ir, const double * __restrict__ ii,
    double * __restrict__ or_, double * __restrict__ oi)
{
    double t0r = ir[0]+ir[2], t0i = ii[0]+ii[2];
    double t1r = ir[0]-ir[2], t1i = ii[0]-ii[2];
    double t2r = ir[1]+ir[3], t2i = ii[1]+ii[3];
    double t3r = ir[1]-ir[3], t3i = ii[1]-ii[3];
    or_[0] = t0r+t2r; oi[0] = t0i+t2i;
    or_[2] = t0r-t2r; oi[2] = t0i-t2i;
    or_[1] = t1r+t3i; oi[1] = t1i-t3r;
    or_[3] = t1r-t3i; oi[3] = t1i+t3r;
}

static inline void dft4_k1_bwd(
    const double * __restrict__ ir, const double * __restrict__ ii,
    double * __restrict__ or_, double * __restrict__ oi)
{
    double t0r = ir[0]+ir[2], t0i = ii[0]+ii[2];
    double t1r = ir[0]-ir[2], t1i = ii[0]-ii[2];
    double t2r = ir[1]+ir[3], t2i = ii[1]+ii[3];
    double t3r = ir[1]-ir[3], t3i = ii[1]-ii[3];
    or_[0] = t0r+t2r; oi[0] = t0i+t2i;
    or_[2] = t0r-t2r; oi[2] = t0i-t2i;
    or_[1] = t1r-t3i; oi[1] = t1i+t3r;
    or_[3] = t1r+t3i; oi[3] = t1i-t3r;
}


/* ═══════════════════════════════════════════════════════════════
 * DFT-8 K=1 — 2×DFT-4 + W8 combine, zero spill
 * 52 flops, all in registers
 * ═══════════════════════════════════════════════════════════════ */

static inline void dft8_k1_fwd(
    const double * __restrict__ ir, const double * __restrict__ ii,
    double * __restrict__ or_, double * __restrict__ oi)
{
    const double c = _k1_S2;

    /* DFT-4 of evens: ir[0],ir[2],ir[4],ir[6] */
    double epr = ir[0]+ir[4], epi = ii[0]+ii[4];
    double eqr = ir[0]-ir[4], eqi = ii[0]-ii[4];
    double err = ir[2]+ir[6], eri = ii[2]+ii[6];
    double esr = ir[2]-ir[6], esi = ii[2]-ii[6];
    double A0r = epr+err, A0i = epi+eri;
    double A2r = epr-err, A2i = epi-eri;
    double A1r = eqr+esi, A1i = eqi-esr;
    double A3r = eqr-esi, A3i = eqi+esr;

    /* DFT-4 of odds: ir[1],ir[3],ir[5],ir[7] */
    double opr = ir[1]+ir[5], opi = ii[1]+ii[5];
    double oqr = ir[1]-ir[5], oqi = ii[1]-ii[5];
    double orr = ir[3]+ir[7], ori = ii[3]+ii[7];
    double osr = ir[3]-ir[7], osi = ii[3]-ii[7];
    double B0r = opr+orr, B0i = opi+ori;
    double B2r = opr-orr, B2i = opi-ori;
    double B1r = oqr+osi, B1i = oqi-osr;
    double B3r = oqr-osi, B3i = oqi+osr;

    /* W8 combine */
    or_[0] = A0r+B0r;       oi[0] = A0i+B0i;
    or_[4] = A0r-B0r;       oi[4] = A0i-B0i;

    double w1r = c*(B1r+B1i), w1i = c*(B1i-B1r);
    or_[1] = A1r+w1r;       oi[1] = A1i+w1i;
    or_[5] = A1r-w1r;       oi[5] = A1i-w1i;

    or_[2] = A2r+B2i;       oi[2] = A2i-B2r;
    or_[6] = A2r-B2i;       oi[6] = A2i+B2r;

    double w3r = -c*(B3r-B3i), w3i = -c*(B3r+B3i);
    or_[3] = A3r+w3r;       oi[3] = A3i+w3i;
    or_[7] = A3r-w3r;       oi[7] = A3i-w3i;
}

static inline void dft8_k1_bwd(
    const double * __restrict__ ir, const double * __restrict__ ii,
    double * __restrict__ or_, double * __restrict__ oi)
{
    const double c = _k1_S2;

    double epr = ir[0]+ir[4], epi = ii[0]+ii[4];
    double eqr = ir[0]-ir[4], eqi = ii[0]-ii[4];
    double err = ir[2]+ir[6], eri = ii[2]+ii[6];
    double esr = ir[2]-ir[6], esi = ii[2]-ii[6];
    double A0r = epr+err, A0i = epi+eri;
    double A2r = epr-err, A2i = epi-eri;
    double A1r = eqr-esi, A1i = eqi+esr;
    double A3r = eqr+esi, A3i = eqi-esr;

    double opr = ir[1]+ir[5], opi = ii[1]+ii[5];
    double oqr = ir[1]-ir[5], oqi = ii[1]-ii[5];
    double orr = ir[3]+ir[7], ori = ii[3]+ii[7];
    double osr = ir[3]-ir[7], osi = ii[3]-ii[7];
    double B0r = opr+orr, B0i = opi+ori;
    double B2r = opr-orr, B2i = opi-ori;
    double B1r = oqr-osi, B1i = oqi+osr;
    double B3r = oqr+osi, B3i = oqi-osr;

    or_[0] = A0r+B0r;       oi[0] = A0i+B0i;
    or_[4] = A0r-B0r;       oi[4] = A0i-B0i;

    double w1r = c*(B1r-B1i), w1i = c*(B1r+B1i);
    or_[1] = A1r+w1r;       oi[1] = A1i+w1i;
    or_[5] = A1r-w1r;       oi[5] = A1i-w1i;

    or_[2] = A2r-B2i;       oi[2] = A2i+B2r;
    or_[6] = A2r+B2i;       oi[6] = A2i-B2r;

    double w3r = -c*(B3r+B3i), w3i = c*(B3r-B3i);
    or_[3] = A3r+w3r;       oi[3] = A3i+w3i;
    or_[7] = A3r-w3r;       oi[7] = A3i-w3i;
}


/* ═══════════════════════════════════════════════════════════════
 * DFT-16 K=1 — 4×4 CT, fused twiddle-before-spill
 *
 * Pass 1: 4 DFT-4 rows, apply internal W16 while hot, then spill
 * Pass 2: 4 DFT-4 columns from spill → output
 *
 * Only 3 non-trivial W16 constants: W16^1, W16^3, √2/2
 * ═══════════════════════════════════════════════════════════════ */

/* Helper: scalar cmul (fwd: re = ar*br - ai*bi, im = ar*bi + ai*br) */
#define _K1_CMUL_FWD(ar,ai,br,bi,dr,di) do { \
    double _t = (ar); \
    (dr) = (ar)*(br) - (ai)*(bi); \
    (di) = _t*(bi) + (ai)*(br); \
} while(0)

/* Helper: negate-cmul (fwd) */
#define _K1_CMUL_NEG_FWD(ar,ai,br,bi,dr,di) do { \
    double _t = (ar); \
    (dr) = -((ar)*(br) - (ai)*(bi)); \
    (di) = -(_t*(bi) + (ai)*(br)); \
} while(0)

/* Helper: scalar cmul (bwd: re = ar*br + ai*bi, im = ai*br - ar*bi) */
#define _K1_CMUL_BWD(ar,ai,br,bi,dr,di) do { \
    double _t = (ar); \
    (dr) = (ar)*(br) + (ai)*(bi); \
    (di) = (ai)*(br) - _t*(bi); \
} while(0)

#define _K1_CMUL_NEG_BWD(ar,ai,br,bi,dr,di) do { \
    double _t = (ar); \
    (dr) = -((ar)*(br) + (ai)*(bi)); \
    (di) = -(((ai)*(br)) - _t*(bi)); \
} while(0)

static inline void dft16_k1_fwd(
    const double * __restrict__ ir, const double * __restrict__ ii,
    double * __restrict__ or_, double * __restrict__ oi)
{
    const double c = _k1_S2;
    const double w1r = _k1_W16_1r, w1i = _k1_W16_1i;
    const double w3r = _k1_W16_3r, w3i = _k1_W16_3i;
    double sp_r[16], sp_i[16];

    /* ═══ Pass 1: 4 rows, DFT-4 + fused internal W16 twiddle → spill ═══ */

    /* Row n2=0: inputs 0,4,8,12 → slots 0,1,2,3. No internal twiddle. */
    {
        double t0r=ir[0]+ir[8],  t0i=ii[0]+ii[8];
        double t1r=ir[0]-ir[8],  t1i=ii[0]-ii[8];
        double t2r=ir[4]+ir[12], t2i=ii[4]+ii[12];
        double t3r=ir[4]-ir[12], t3i=ii[4]-ii[12];
        sp_r[0]=t0r+t2r; sp_i[0]=t0i+t2i;
        sp_r[1]=t1r+t3i; sp_i[1]=t1i-t3r;
        sp_r[2]=t0r-t2r; sp_i[2]=t0i-t2i;
        sp_r[3]=t1r-t3i; sp_i[3]=t1i+t3r;
    }
    /* Row n2=1: inputs 1,5,9,13 → slots 4,5,6,7. Twiddle: d1*=W1, d2*=W8^1, d3*=W3 */
    {
        double t0r=ir[1]+ir[9],  t0i=ii[1]+ii[9];
        double t1r=ir[1]-ir[9],  t1i=ii[1]-ii[9];
        double t2r=ir[5]+ir[13], t2i=ii[5]+ii[13];
        double t3r=ir[5]-ir[13], t3i=ii[5]-ii[13];
        double d0r=t0r+t2r, d0i=t0i+t2i;
        double d1r=t1r+t3i, d1i=t1i-t3r;
        double d2r=t0r-t2r, d2i=t0i-t2i;
        double d3r=t1r-t3i, d3i=t1i+t3r;
        sp_r[4]=d0r; sp_i[4]=d0i;
        _K1_CMUL_FWD(d1r,d1i,w1r,w1i, sp_r[5],sp_i[5]);
        /* W8^1: c*(r+i), c*(i-r) */
        sp_r[6]=c*(d2r+d2i); sp_i[6]=c*(d2i-d2r);
        _K1_CMUL_FWD(d3r,d3i,w3r,w3i, sp_r[7],sp_i[7]);
    }
    /* Row n2=2: inputs 2,6,10,14 → slots 8,9,10,11. Twiddle: d1*=W8^1, d2*=-j, d3*=W8^3 */
    {
        double t0r=ir[2]+ir[10], t0i=ii[2]+ii[10];
        double t1r=ir[2]-ir[10], t1i=ii[2]-ii[10];
        double t2r=ir[6]+ir[14], t2i=ii[6]+ii[14];
        double t3r=ir[6]-ir[14], t3i=ii[6]-ii[14];
        double d0r=t0r+t2r, d0i=t0i+t2i;
        double d1r=t1r+t3i, d1i=t1i-t3r;
        double d2r=t0r-t2r, d2i=t0i-t2i;
        double d3r=t1r-t3i, d3i=t1i+t3r;
        sp_r[8]=d0r; sp_i[8]=d0i;
        sp_r[9]=c*(d1r+d1i); sp_i[9]=c*(d1i-d1r);
        /* -j: re=im, im=-re */
        sp_r[10]=d2i; sp_i[10]=-d2r;
        /* W8^3: c*(i-r), -(c*(r+i)) */
        sp_r[11]=c*(d3i-d3r); sp_i[11]=-(c*(d3r+d3i));
    }
    /* Row n2=3: inputs 3,7,11,15 → slots 12,13,14,15. Twiddle: d1*=W3, d2*=W8^3, d3*=-W1 */
    {
        double t0r=ir[3]+ir[11], t0i=ii[3]+ii[11];
        double t1r=ir[3]-ir[11], t1i=ii[3]-ii[11];
        double t2r=ir[7]+ir[15], t2i=ii[7]+ii[15];
        double t3r=ir[7]-ir[15], t3i=ii[7]-ii[15];
        double d0r=t0r+t2r, d0i=t0i+t2i;
        double d1r=t1r+t3i, d1i=t1i-t3r;
        double d2r=t0r-t2r, d2i=t0i-t2i;
        double d3r=t1r-t3i, d3i=t1i+t3r;
        sp_r[12]=d0r; sp_i[12]=d0i;
        _K1_CMUL_FWD(d1r,d1i,w3r,w3i, sp_r[13],sp_i[13]);
        sp_r[14]=c*(d2i-d2r); sp_i[14]=-(c*(d2r+d2i));
        _K1_CMUL_NEG_FWD(d3r,d3i,w1r,w1i, sp_r[15],sp_i[15]);
    }

    /* ═══ Pass 2: 4 columns from spill → output ═══ */
#define _K1_COL16(s0,s1,s2,s3, o0,o1,o2,o3) do { \
    double t0r=sp_r[s0]+sp_r[s2], t0i=sp_i[s0]+sp_i[s2]; \
    double t1r=sp_r[s0]-sp_r[s2], t1i=sp_i[s0]-sp_i[s2]; \
    double t2r=sp_r[s1]+sp_r[s3], t2i=sp_i[s1]+sp_i[s3]; \
    double t3r=sp_r[s1]-sp_r[s3], t3i=sp_i[s1]-sp_i[s3]; \
    or_[o0]=t0r+t2r; oi[o0]=t0i+t2i; \
    or_[o2]=t0r-t2r; oi[o2]=t0i-t2i; \
    or_[o1]=t1r+t3i; oi[o1]=t1i-t3r; \
    or_[o3]=t1r-t3i; oi[o3]=t1i+t3r; \
} while(0)
    _K1_COL16(0, 4, 8,12,  0, 4, 8,12);
    _K1_COL16(1, 5, 9,13,  1, 5, 9,13);
    _K1_COL16(2, 6,10,14,  2, 6,10,14);
    _K1_COL16(3, 7,11,15,  3, 7,11,15);
#undef _K1_COL16
}

static inline void dft16_k1_bwd(
    const double * __restrict__ ir, const double * __restrict__ ii,
    double * __restrict__ or_, double * __restrict__ oi)
{
    const double c = _k1_S2;
    const double w1r = _k1_W16_1r, w1i = -_k1_W16_1i;  /* conjugated */
    const double w3r = _k1_W16_3r, w3i = -_k1_W16_3i;
    double sp_r[16], sp_i[16];

    /* Pass 1: rows bwd + conjugated internal twiddles */
    {
        double t0r=ir[0]+ir[8],  t0i=ii[0]+ii[8];
        double t1r=ir[0]-ir[8],  t1i=ii[0]-ii[8];
        double t2r=ir[4]+ir[12], t2i=ii[4]+ii[12];
        double t3r=ir[4]-ir[12], t3i=ii[4]-ii[12];
        sp_r[0]=t0r+t2r; sp_i[0]=t0i+t2i;
        sp_r[1]=t1r-t3i; sp_i[1]=t1i+t3r;  /* bwd: -j → +j */
        sp_r[2]=t0r-t2r; sp_i[2]=t0i-t2i;
        sp_r[3]=t1r+t3i; sp_i[3]=t1i-t3r;
    }
    {
        double t0r=ir[1]+ir[9],  t0i=ii[1]+ii[9];
        double t1r=ir[1]-ir[9],  t1i=ii[1]-ii[9];
        double t2r=ir[5]+ir[13], t2i=ii[5]+ii[13];
        double t3r=ir[5]-ir[13], t3i=ii[5]-ii[13];
        double d0r=t0r+t2r, d0i=t0i+t2i;
        double d1r=t1r-t3i, d1i=t1i+t3r;
        double d2r=t0r-t2r, d2i=t0i-t2i;
        double d3r=t1r+t3i, d3i=t1i-t3r;
        sp_r[4]=d0r; sp_i[4]=d0i;
        _K1_CMUL_BWD(d1r,d1i,_k1_W16_1r,_k1_W16_1i, sp_r[5],sp_i[5]);
        /* conj(W8^1): c*(r-i), c*(r+i) */
        sp_r[6]=c*(d2r-d2i); sp_i[6]=c*(d2r+d2i);
        _K1_CMUL_BWD(d3r,d3i,_k1_W16_3r,_k1_W16_3i, sp_r[7],sp_i[7]);
    }
    {
        double t0r=ir[2]+ir[10], t0i=ii[2]+ii[10];
        double t1r=ir[2]-ir[10], t1i=ii[2]-ii[10];
        double t2r=ir[6]+ir[14], t2i=ii[6]+ii[14];
        double t3r=ir[6]-ir[14], t3i=ii[6]-ii[14];
        double d0r=t0r+t2r, d0i=t0i+t2i;
        double d1r=t1r-t3i, d1i=t1i+t3r;
        double d2r=t0r-t2r, d2i=t0i-t2i;
        double d3r=t1r+t3i, d3i=t1i-t3r;
        sp_r[8]=d0r; sp_i[8]=d0i;
        sp_r[9]=c*(d1r-d1i); sp_i[9]=c*(d1r+d1i);
        /* +j: re=-im, im=re */
        sp_r[10]=-d2i; sp_i[10]=d2r;
        /* conj(W8^3): -(c*(r+i)), c*(r-i) */
        sp_r[11]=-(c*(d3r+d3i)); sp_i[11]=c*(d3r-d3i);
    }
    {
        double t0r=ir[3]+ir[11], t0i=ii[3]+ii[11];
        double t1r=ir[3]-ir[11], t1i=ii[3]-ii[11];
        double t2r=ir[7]+ir[15], t2i=ii[7]+ii[15];
        double t3r=ir[7]-ir[15], t3i=ii[7]-ii[15];
        double d0r=t0r+t2r, d0i=t0i+t2i;
        double d1r=t1r-t3i, d1i=t1i+t3r;
        double d2r=t0r-t2r, d2i=t0i-t2i;
        double d3r=t1r+t3i, d3i=t1i-t3r;
        sp_r[12]=d0r; sp_i[12]=d0i;
        _K1_CMUL_BWD(d1r,d1i,_k1_W16_3r,_k1_W16_3i, sp_r[13],sp_i[13]);
        sp_r[14]=-(c*(d2r+d2i)); sp_i[14]=c*(d2r-d2i);
        _K1_CMUL_NEG_BWD(d3r,d3i,_k1_W16_1r,_k1_W16_1i, sp_r[15],sp_i[15]);
    }

    /* Pass 2: columns bwd */
#define _K1_COL16B(s0,s1,s2,s3, o0,o1,o2,o3) do { \
    double t0r=sp_r[s0]+sp_r[s2], t0i=sp_i[s0]+sp_i[s2]; \
    double t1r=sp_r[s0]-sp_r[s2], t1i=sp_i[s0]-sp_i[s2]; \
    double t2r=sp_r[s1]+sp_r[s3], t2i=sp_i[s1]+sp_i[s3]; \
    double t3r=sp_r[s1]-sp_r[s3], t3i=sp_i[s1]-sp_i[s3]; \
    or_[o0]=t0r+t2r; oi[o0]=t0i+t2i; \
    or_[o2]=t0r-t2r; oi[o2]=t0i-t2i; \
    or_[o1]=t1r-t3i; oi[o1]=t1i+t3r; \
    or_[o3]=t1r+t3i; oi[o3]=t1i-t3r; \
} while(0)
    _K1_COL16B(0, 4, 8,12,  0, 4, 8,12);
    _K1_COL16B(1, 5, 9,13,  1, 5, 9,13);
    _K1_COL16B(2, 6,10,14,  2, 6,10,14);
    _K1_COL16B(3, 7,11,15,  3, 7,11,15);
#undef _K1_COL16B
}


/* ═══════════════════════════════════════════════════════════════
 * DFT-32 K=1 — 8×4 CT, fused twiddle-before-spill
 *
 * Pass 1: 4 DFT-8 rows, apply internal W32 while hot, then spill
 * Pass 2: 8 DFT-4 columns from spill → output
 * ═══════════════════════════════════════════════════════════════ */

/* Inline DFT-8 building block: 8 inputs at stride S, 8 outputs to dst[] */
#define _K1_DFT8_FWD(ir,ii,S, d0r,d0i,d1r,d1i,d2r,d2i,d3r,d3i,d4r,d4i,d5r,d5i,d6r,d6i,d7r,d7i) do { \
    const double _c = _k1_S2; \
    double _epr=ir[0*S]+ir[4*S],_epi=ii[0*S]+ii[4*S]; \
    double _eqr=ir[0*S]-ir[4*S],_eqi=ii[0*S]-ii[4*S]; \
    double _err=ir[2*S]+ir[6*S],_eri=ii[2*S]+ii[6*S]; \
    double _esr=ir[2*S]-ir[6*S],_esi=ii[2*S]-ii[6*S]; \
    double _A0r=_epr+_err,_A0i=_epi+_eri; \
    double _A2r=_epr-_err,_A2i=_epi-_eri; \
    double _A1r=_eqr+_esi,_A1i=_eqi-_esr; \
    double _A3r=_eqr-_esi,_A3i=_eqi+_esr; \
    double _opr=ir[1*S]+ir[5*S],_opi=ii[1*S]+ii[5*S]; \
    double _oqr=ir[1*S]-ir[5*S],_oqi=ii[1*S]-ii[5*S]; \
    double _orr=ir[3*S]+ir[7*S],_ori=ii[3*S]+ii[7*S]; \
    double _osr=ir[3*S]-ir[7*S],_osi=ii[3*S]-ii[7*S]; \
    double _B0r=_opr+_orr,_B0i=_opi+_ori; \
    double _B2r=_opr-_orr,_B2i=_opi-_ori; \
    double _B1r=_oqr+_osi,_B1i=_oqi-_osr; \
    double _B3r=_oqr-_osi,_B3i=_oqi+_osr; \
    double _w1r=_c*(_B1r+_B1i),_w1i=_c*(_B1i-_B1r); \
    double _w3r=-_c*(_B3r-_B3i),_w3i=-_c*(_B3r+_B3i); \
    d0r=_A0r+_B0r; d0i=_A0i+_B0i; \
    d4r=_A0r-_B0r; d4i=_A0i-_B0i; \
    d1r=_A1r+_w1r; d1i=_A1i+_w1i; \
    d5r=_A1r-_w1r; d5i=_A1i-_w1i; \
    d2r=_A2r+_B2i; d2i=_A2i-_B2r; \
    d6r=_A2r-_B2i; d6i=_A2i+_B2r; \
    d3r=_A3r+_w3r; d3i=_A3i+_w3i; \
    d7r=_A3r-_w3r; d7i=_A3i-_w3i; \
} while(0)

static inline void dft32_k1_fwd(
    const double * __restrict__ ir, const double * __restrict__ ii,
    double * __restrict__ or_, double * __restrict__ oi)
{
    double sp_r[32], sp_i[32];

    /* ═══ Pass 1: 4 DFT-8 rows, stride=4 within input ═══ */

    /* Row n2=0: inputs 0,4,8,12,16,20,24,28. No internal twiddle. */
    _K1_DFT8_FWD(ir,ii,4,
        sp_r[0],sp_i[0],sp_r[1],sp_i[1],sp_r[2],sp_i[2],sp_r[3],sp_i[3],
        sp_r[4],sp_i[4],sp_r[5],sp_i[5],sp_r[6],sp_i[6],sp_r[7],sp_i[7]);

    /* Row n2=1: inputs 1,5,9,13,17,21,25,29. Internal W32^k1 for k1=1..7 */
    {
        double d0r,d0i,d1r,d1i,d2r,d2i,d3r,d3i,d4r,d4i,d5r,d5i,d6r,d6i,d7r,d7i;
        _K1_DFT8_FWD((&ir[1]),(&ii[1]),4,
            d0r,d0i,d1r,d1i,d2r,d2i,d3r,d3i,d4r,d4i,d5r,d5i,d6r,d6i,d7r,d7i);
        sp_r[8]=d0r;  sp_i[8]=d0i;
        _K1_CMUL_FWD(d1r,d1i,_k1_W32_1r,_k1_W32_1i, sp_r[9],sp_i[9]);
        _K1_CMUL_FWD(d2r,d2i,_k1_W32_2r,_k1_W32_2i, sp_r[10],sp_i[10]);
        _K1_CMUL_FWD(d3r,d3i,_k1_W32_3r,_k1_W32_3i, sp_r[11],sp_i[11]);
        _K1_CMUL_FWD(d4r,d4i,_k1_W32_4r,_k1_W32_4i, sp_r[12],sp_i[12]);
        _K1_CMUL_FWD(d5r,d5i,_k1_W32_5r,_k1_W32_5i, sp_r[13],sp_i[13]);
        _K1_CMUL_FWD(d6r,d6i,_k1_W32_6r,_k1_W32_6i, sp_r[14],sp_i[14]);
        _K1_CMUL_FWD(d7r,d7i,_k1_W32_7r,_k1_W32_7i, sp_r[15],sp_i[15]);
    }

    /* Row n2=2: inputs 2,6,10,14,18,22,26,30. Internal W32^(2*k1) */
    {
        double d0r,d0i,d1r,d1i,d2r,d2i,d3r,d3i,d4r,d4i,d5r,d5i,d6r,d6i,d7r,d7i;
        _K1_DFT8_FWD((&ir[2]),(&ii[2]),4,
            d0r,d0i,d1r,d1i,d2r,d2i,d3r,d3i,d4r,d4i,d5r,d5i,d6r,d6i,d7r,d7i);
        sp_r[16]=d0r; sp_i[16]=d0i;
        _K1_CMUL_FWD(d1r,d1i,_k1_W32_2r,_k1_W32_2i, sp_r[17],sp_i[17]);
        _K1_CMUL_FWD(d2r,d2i,_k1_W32_4r,_k1_W32_4i, sp_r[18],sp_i[18]);
        _K1_CMUL_FWD(d3r,d3i,_k1_W32_6r,_k1_W32_6i, sp_r[19],sp_i[19]);
        _K1_CMUL_FWD(d4r,d4i,_k1_W32_8r,_k1_W32_8i, sp_r[20],sp_i[20]);
        _K1_CMUL_FWD(d5r,d5i,_k1_W32_10r,_k1_W32_10i, sp_r[21],sp_i[21]);
        _K1_CMUL_FWD(d6r,d6i,_k1_W32_12r,_k1_W32_12i, sp_r[22],sp_i[22]);
        _K1_CMUL_FWD(d7r,d7i,_k1_W32_14r,_k1_W32_14i, sp_r[23],sp_i[23]);
    }

    /* Row n2=3: inputs 3,7,11,15,19,23,27,31. Internal W32^(3*k1) */
    {
        double d0r,d0i,d1r,d1i,d2r,d2i,d3r,d3i,d4r,d4i,d5r,d5i,d6r,d6i,d7r,d7i;
        _K1_DFT8_FWD((&ir[3]),(&ii[3]),4,
            d0r,d0i,d1r,d1i,d2r,d2i,d3r,d3i,d4r,d4i,d5r,d5i,d6r,d6i,d7r,d7i);
        sp_r[24]=d0r; sp_i[24]=d0i;
        _K1_CMUL_FWD(d1r,d1i,_k1_W32_3r,_k1_W32_3i, sp_r[25],sp_i[25]);
        _K1_CMUL_FWD(d2r,d2i,_k1_W32_6r,_k1_W32_6i, sp_r[26],sp_i[26]);
        _K1_CMUL_FWD(d3r,d3i,_k1_W32_9r,_k1_W32_9i, sp_r[27],sp_i[27]);
        _K1_CMUL_FWD(d4r,d4i,_k1_W32_12r,_k1_W32_12i, sp_r[28],sp_i[28]);
        _K1_CMUL_FWD(d5r,d5i,_k1_W32_15r,_k1_W32_15i, sp_r[29],sp_i[29]);
        _K1_CMUL_FWD(d6r,d6i,_k1_W32_18r,_k1_W32_18i, sp_r[30],sp_i[30]);
        _K1_CMUL_FWD(d7r,d7i,_k1_W32_21r,_k1_W32_21i, sp_r[31],sp_i[31]);
    }

    /* ═══ Pass 2: 8 DFT-4 columns from spill → output ═══ */
#define _K1_COL32(s0,s1,s2,s3, o0,o1,o2,o3) do { \
    double t0r=sp_r[s0]+sp_r[s2], t0i=sp_i[s0]+sp_i[s2]; \
    double t1r=sp_r[s0]-sp_r[s2], t1i=sp_i[s0]-sp_i[s2]; \
    double t2r=sp_r[s1]+sp_r[s3], t2i=sp_i[s1]+sp_i[s3]; \
    double t3r=sp_r[s1]-sp_r[s3], t3i=sp_i[s1]-sp_i[s3]; \
    or_[o0]=t0r+t2r; oi[o0]=t0i+t2i; \
    or_[o2]=t0r-t2r; oi[o2]=t0i-t2i; \
    or_[o1]=t1r+t3i; oi[o1]=t1i-t3r; \
    or_[o3]=t1r-t3i; oi[o3]=t1i+t3r; \
} while(0)
    _K1_COL32(0, 8,16,24,  0, 8,16,24);
    _K1_COL32(1, 9,17,25,  1, 9,17,25);
    _K1_COL32(2,10,18,26,  2,10,18,26);
    _K1_COL32(3,11,19,27,  3,11,19,27);
    _K1_COL32(4,12,20,28,  4,12,20,28);
    _K1_COL32(5,13,21,29,  5,13,21,29);
    _K1_COL32(6,14,22,30,  6,14,22,30);
    _K1_COL32(7,15,23,31,  7,15,23,31);
#undef _K1_COL32
}

#undef _K1_CMUL_FWD
#undef _K1_CMUL_NEG_FWD
#undef _K1_CMUL_BWD
#undef _K1_CMUL_NEG_BWD

#endif /* FFT_N1_K1_H */
